-- =====================================================================
CREATE OR REPLACE FUNCTION OFSERM.DERIVATIVE_PLACED_COLLATERALS_DATA_CREATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_DERIVATIVES(N_CLEARED_TXN_BANK_ROLE_ID,N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,N_INSTRUMENT_SKEY,F_CORE_INVESTMENT_COMPANY_IND,F_REGULATED_FIN_ENTITY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,F_CLEARED_TRANSACTION_FLAG,F_FAILED_TRADE_FLAG,F_INTERNAL_CUST_IND,F_LONG_SETTLEMENT_TXN_FLAG,F_MATERIALITY_FLAG,F_NETTABILITY_FLAG,F_PREF_TREATMENT_FLAG,F_QUALIFIED_CCP_FLAG,F_RW_BY_DISCRETION,N_BUSINESS_DAYS_LONG_TXN,N_CENTRAL_COUNTERPARTY_SKEY,N_CLEARING_MEMBER_SKEY,N_COLLATERAL_FAIR_VALUE,N_COVERED_RWA_UL,N_EFFECTIVE_EXP_AMT,N_EFF_MATURITY,N_EL_AMOUNT,N_EXCHANGE_RATE,N_EXPOSURE_AMOUNT,N_EXP_COVERED_AMT,N_EXP_UNCOVERED_AMT,N_FAILED_BUSINESS_DAYS,N_ISSUE_SKEY,N_MORTGAGE_LENDING_VALUE,N_ORIGINAL_MATURITY,N_PRE_MITIGATION_EL_AMT,N_PRE_MITIGATION_RWA_EL,N_RESIDUAL_MATURITY,N_RUN_PARAMETER_SETUP_SKEY,N_RUN_SKEY,N_RWA_EL_AMT,N_RWA_UL_AMT,N_SHAREHOLDING_PERCENT,N_STD_BUSINESS_DAYS,N_SUPERVISORY_BETA_VALUE,N_UNCOVERED_RWA_UL,V_APPROACH_TYPE,V_DATA_SOURCE,N_ENTITY_SKEY,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,V_EXP_RCY_CODE,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,N_STD_SENIORITY_SKEY,D_EXPOSURE_END_DATE,D_EXPOSURE_START_DATE,F_CLEARED_TXN_COLLATERAL,F_COLL_BANKRUPTCY_REMOTE_FLAG,F_COLL_COVERS_ALL_LOSSES,F_ILLIQUID_COLLATERAL,N_ADJUSTED_LGD_PERCENT,N_EXP_SENIORITY,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,N_REMARGIN_FREQUENCY,N_REVALUATION_FREQUENCY,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_CLEARED_TXN_BANK_ROLE.N_CLEARED_TXN_BANK_ROLE_ID),to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY),DIM_PARTY.F_CORE_INVESTMENT_COMPANY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),STG_PLACED_COLLATERAL.F_CLEARED_TRANSACTION_FLAG,'N',CASE  WHEN dim_basel_cap_consl_appr_cust.n_basel_cap_consl_appr_skey is not null THEN 'Y' ELSE 'N' END,'N','Y','N','N',DIM_PARTY_CCP.f_qualified_ccp_flag,'N',0,DIM_PARTY_CCP.N_PARTY_SKEY,CASE WHEN STG_PLACED_COLLATERAL.v_cleared_txn_bank_role_code = 'CMC' THEN DIM_PARTY. N_PARTY_SKEY END,FSI_INSTR_VALUATION_DETAILS.N_FAIR_VALUE*FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,0,0,CASE WHEN FSI_ACCT_MODELING_INFO.N_EFF_MATURITY IS NULL THEN TRUNC(COALESCE(STG_PLACED_COLLATERAL.D_MATURITY_DATE,DIM_INSTRUMENT_CONTRACT.D_MATURITY_DATE) - STG_PLACED_COLLATERAL.FIC_MIS_DATE)/365 ELSE FSI_ACCT_MODELING_INFO.N_EFF_MATURITY END,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_INSTR_VALUATION_DETAILS.N_FAIR_VALUE*FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,0,0,0,DIM_ISSUE.N_ISSUE_SKEY,0,TRUNC(STG_PLACED_COLLATERAL.d_maturity_date - STG_PLACED_COLLATERAL.d_start_date)/365,0,0,TRUNC(COALESCE(STG_PLACED_COLLATERAL.D_MATURITY_DATE,DIM_INSTRUMENT_CONTRACT.D_MATURITY_DATE) - STG_PLACED_COLLATERAL.FIC_MIS_DATE)/365,RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY,'870',0,0,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,0,0,0,FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,'STG_PLACED_COLLATERAL',to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,FSI_CAP_RUN_EXE_PARAMETERS.V_RCY_CODE,to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(FSI_SENIORITY_RECLASSIFICATION.N_STD_SENIORITY_SKEY),STG_PLACED_COLLATERAL.D_MATURITY_DATE,STG_PLACED_COLLATERAL.D_START_DATE,STG_PLACED_COLLATERAL.F_CLEARED_TRANSACTION_FLAG,STG_PLACED_COLLATERAL.F_COLL_BANKRUPTCY_REMOTE_FLAG,STG_PLACED_COLLATERAL.F_COLL_COVERS_ALL_LOSSES,STG_PLACED_COLLATERAL.F_ILLIQUID_COLLATERAL,to_char(STG_PLACED_COLLATERAL.N_ADJUSTED_LGD_PERCENT),to_char(STG_PLACED_COLLATERAL.N_INSTRUMENT_SENIORITY),to_char(STG_PLACED_COLLATERAL.N_LGD_PERCENT),to_char(STG_PLACED_COLLATERAL.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(STG_PLACED_COLLATERAL.N_PD_PERCENT),to_char(STG_PLACED_COLLATERAL.N_REMARGIN_FREQUENCY),to_char(STG_PLACED_COLLATERAL.N_REVAL_FREQUENCY),STG_PLACED_COLLATERAL.V_CCY_CODE FROM STG_PLACED_COLLATERAL INNER JOIN DIM_DATES ON STG_PLACED_COLLATERAL.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_EXPOSURE ON STG_PLACED_COLLATERAL.V_POSTED_COLLATERAL_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE INNER JOIN DIM_GAAP ON STG_PLACED_COLLATERAL.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE INNER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' AND DIM_DATES.N_DATE_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY INNER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' INNER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'OTH_PLACED_COLL_EXP' INNER JOIN fsi_placed_collateral ON fsi_placed_collateral.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND fsi_placed_collateral.N_RUN_SKEY = '870' AND fsi_placed_collateral.N_GAAP_SKEY = DIM_GAAP.N_GAAP_SKEY AND fsi_placed_collateral.N_POSTED_COLLATERAL_SKEY = DIM_EXPOSURE.n_acct_skey AND fsi_placed_collateral.N_CAP_APPROACH_TYPE_SKEY = FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY AND fsi_placed_collateral.N_CAP_RECORD_TYPE_SKEY = FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY INNER JOIN DIM_COUNTRY ON COALESCE(STG_PLACED_COLLATERAL.V_COUNTRY_CODE, 'MSG') = DIM_COUNTRY.V_COUNTRY_ID AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE INNER JOIN DIM_PRODUCT ON STG_PLACED_COLLATERAL.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE INNER JOIN DIM_PARTY ON COALESCE(STG_PLACED_COLLATERAL.V_PARTY_CODE, 'MSG') = DIM_PARTY.V_PARTY_ID AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE INNER JOIN DIM_PARTY_TYPE ON COALESCE(DIM_PARTY.V_PARTY_TYPE, 'MSG') = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE INNER JOIN FCT_ENTITY_INFO ON STG_PLACED_COLLATERAL.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'N') = 'Y' INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ) LEFT OUTER JOIN FCT_ENTITY_INFO FCT_ENTITY_INFO_CUST ON FCT_ENTITY_INFO.V_ENTITY_CODE = STG_PLACED_COLLATERAL.V_PARTY_CODE AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND = 'Y' LEFT OUTER JOIN DIM_BASEL_CAP_CONSL_APPR DIM_BASEL_CAP_CONSL_APPR_CUST ON DIM_BASEL_CAP_CONSL_APPR_CUST.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR_CUST.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ,'FAGR' ,'PRAGR' ) /*INNER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY   AND DIM_DATES.N_DATE_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY  INNER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY   AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY   AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' INNER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY   AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY   AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY  INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE  INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'OTH_PLACED_COLL_EXP'*/ INNER JOIN DIM_PARTY DIM_PARTY_CCP ON COALESCE(STG_PLACED_COLLATERAL.V_CENTRAL_COUNTERPARTY_CODE, 'MSG') = DIM_PARTY_CCP.V_PARTY_ID AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_PARTY_CCP.D_RECORD_START_DATE AND DIM_PARTY_CCP.D_RECORD_END_DATE LEFT OUTER JOIN DIM_CLEARED_TXN_BANK_ROLE ON STG_PLACED_COLLATERAL.V_CLEARED_TXN_BANK_ROLE_CODE = DIM_CLEARED_TXN_BANK_ROLE.V_CLEARED_TXN_BANK_ROLE_CODE AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_CLEARED_TXN_BANK_ROLE.D_RECORD_START_DATE AND DIM_CLEARED_TXN_BANK_ROLE.D_RECORD_END_DATE INNER JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT OUTER JOIN FSI_INSTR_VALUATION_DETAILS ON FSI_INSTR_VALUATION_DETAILS.V_INSTRUMENT_CODE = STG_PLACED_COLLATERAL.V_INSTRUMENT_CODE AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN FSI_INSTR_VALUATION_DETAILS.D_RECORD_START_DATE AND FSI_INSTR_VALUATION_DETAILS.D_RECORD_END_DATE LEFT OUTER JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_PLACED_COLLATERAL.V_INSTRUMENT_CODE AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE /*INNER JOIN FSI_ACCT_PLACED_COLL_MAP ON FSI_ACCT_PLACED_COLL_MAP.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY   AND FSI_ACCT_PLACED_COLL_MAP.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY   AND FSI_ACCT_PLACED_COLL_MAP.N_POSTED_COLLATERAL_SKEY = DIM_EXPOSURE.N_ACCT_SKEY  INNER JOIN FSI_CAP_DERIVATIVES ON FSI_CAP_DERIVATIVES.N_ACCT_SKEY = FSI_ACCT_PLACED_COLL_MAP.N_ACCT_SKEY   AND FSI_CAP_DERIVATIVES.N_RUN_SKEY = FSI_ACCT_PLACED_COLL_MAP.N_RUN_SKEY   AND FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY = FSI_ACCT_PLACED_COLL_MAP.N_MIS_DATE_SKEY   AND FSI_CAP_DERIVATIVES.N_GAAP_SKEY = DIM_GAAP.N_GAAP_SKEY   AND FSI_CAP_DERIVATIVES.N_CAP_APPROACH_TYPE_SKEY = FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY   AND FSI_CAP_DERIVATIVES.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE*/ LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_PLACED_COLLATERAL.V_CCY_CODE LEFT OUTER JOIN FSI_SENIORITY_RECLASSIFICATION ON FSI_SENIORITY_RECLASSIFICATION.N_SENIORITY = STG_PLACED_COLLATERAL.N_INSTRUMENT_SENIORITY AND FSI_SENIORITY_RECLASSIFICATION.N_RUN_SKEY = '870' AND FSI_SENIORITY_RECLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT OUTER JOIN FSI_PROD_TXN_TYPE_RECLASS ON FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY AND FSI_PROD_TXN_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_PROD_TXN_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY /*LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE DIM_BASEL_PRODUCT_TYPE_LVL1 ON DIM_BASEL_PRODUCT_TYPE_LVL1.N_BASEL_PROD_TYPE_SKEY = FSI_CAP_DERIVATIVES.N_BASEL_PROD_TYPE_SKEY*/ LEFT OUTER JOIN FSI_PARTY_GRADE_RECLASS ON FSI_PARTY_GRADE_RECLASS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY AND FSI_PARTY_GRADE_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_PARTY_GRADE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_GRADE_RECLASS.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT OUTER JOIN DIM_ISSUE ON DIM_ISSUE.V_ISSUE_CODE = COALESCE(STG_PLACED_COLLATERAL.V_INSTRUMENT_CODE, DIM_EXPOSURE.V_EXPOSURE_ID) AND STG_PLACED_COLLATERAL.FIC_MIS_DATE BETWEEN DIM_ISSUE.D_RECORD_START_DATE AND DIM_ISSUE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_ACCT_MODELING_INFO ON FSI_ACCT_MODELING_INFO.V_EXPOSURE_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN FSI_ACCT_MODELING_INFO.D_RECORD_START_DATE AND FSI_ACCT_MODELING_INFO.D_RECORD_END_DATE WHERE 1=1 AND COALESCE(STG_PLACED_COLLATERAL.V_MARGIN_TYPE, 'MSG') NOT IN ( 'DF' ) AND (TRUNC(COALESCE(STG_PLACED_COLLATERAL.D_MATURITY_DATE,DIM_INSTRUMENT_CONTRACT.D_MATURITY_DATE) - STG_PLACED_COLLATERAL.FIC_MIS_DATE)/365)>0 LOG ERRORS INTO FSI_CAP_DERIVATIVES$ ('1776768458822_15974601_20260331_1_Job_c4ace55495864a49afa8bacd8b44d938') REJECT LIMIT UNLIMITED;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
